#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    int g;
    int x;
    int y;
} XgcdResult;

XgcdResult xgcd(int b, int n) {
    XgcdResult result;
    int x0 = 1, x1 = 0, y0 = 0, y1 = 1;
    while (n != 0) {
        int q = b / n;
        int temp = b;
        b = n;
        n = temp % n;
        temp = x0;
        x0 = x1;
        x1 = temp - q * x1;
        temp = y0;
        y0 = y1;
        y1 = temp - q * y1;
    }
    result.g = b;
    result.x = x0;
    result.y = y0;
    return result;
}

int max(int a, int b) {
    return a > b ? a : b;
}

int main() {
    int a, aa, b, bb, l, r;
    scanf("%d %d %d %d %d %d", &a, &aa, &b, &bb, &l, &r);
    XgcdResult res = xgcd(a, b);
    int g = res.g;
    int x = res.x;
    int y = res.y;
    int c = bb - aa;
    if (c % g != 0) {
        printf("0\n");
        return 0;
    }
    int i = a * (x * c) / g + aa;
    int ii = (-b * (y * c) / g) + bb;
    int step = a * b / g;
    if ((ii - i) % step != 0) {
        printf("0\n");
        return 0;
    }
    if (i > max(aa, bb)) {
        i -= ((i - max(aa, bb)) / step) * step;
    } else if (i < max(aa, bb)) {
        int diff = max(aa, bb) - i;
        i += (diff / step + (diff % step != 0 ? 1 : 0)) * step;
    }
